import type { DungeonDiary } from "@harness/diary";

import { ArtifactViewer } from "@/components/artifacts/ArtifactViewer";
import type { ArtifactViewerModel } from "@/components/artifacts/model";

import { DiaryPanel } from "./DiaryPanel";
import styles from "./DiaryLayer.module.css";

export type DiaryLayerTab = "diary" | "artifacts";

type DiaryLayerProps = {
  readonly diary: DungeonDiary;
  readonly artifactModel: ArtifactViewerModel | null;
  readonly activeTab: DiaryLayerTab;
  readonly onSelectTab: (tab: DiaryLayerTab) => void;
  readonly onClose: () => void;
};

export function DiaryLayer({
  diary,
  artifactModel,
  activeTab,
  onSelectTab,
  onClose,
}: DiaryLayerProps) {
  return (
    <div
      className={styles.scrim}
      aria-label="Diary and artifacts layer"
      data-testid="diary-layer"
    >
      <section className={styles.layer} role="dialog" aria-modal="false">
        <header className={styles.header}>
          <div>
            <h2>The Deep's manuscript</h2>
            <p>
              Floor {diary.summary.depth} · turn {diary.summary.turns}
            </p>
          </div>
          <div className={styles.controls}>
            <div className={styles.tabs} role="tablist" aria-label="Second layer tabs">
              <button
                type="button"
                role="tab"
                aria-selected={activeTab === "diary"}
                data-selected={activeTab === "diary" ? "true" : "false"}
                data-testid="diary-tab"
                onClick={() => onSelectTab("diary")}
              >
                Diary
              </button>
              <button
                type="button"
                role="tab"
                aria-selected={activeTab === "artifacts"}
                data-selected={activeTab === "artifacts" ? "true" : "false"}
                data-testid="artifacts-tab"
                onClick={() => onSelectTab("artifacts")}
              >
                Artifacts
              </button>
            </div>
            <button className={styles.close} type="button" onClick={onClose}>
              Close
            </button>
          </div>
        </header>

        <div className={styles.content}>
          {activeTab === "diary" ? (
            <DiaryPanel diary={diary} variant="partial" />
          ) : (
            <ArtifactViewer model={artifactModel} />
          )}
        </div>
      </section>
    </div>
  );
}
"use client";

import type { DungeonDiary, DiaryEntryKind } from "@harness/diary";

import styles from "./DiaryPanel.module.css";

type DiaryPanelProps = {
  readonly diary: DungeonDiary;
  readonly variant: "partial" | "final";
};

export function DiaryPanel({ diary, variant }: DiaryPanelProps) {
  return (
    <section
      className={[styles.panel, variant === "final" ? styles.final : ""]
        .filter(Boolean)
        .join(" ")}
      aria-label="Dungeon diary"
      data-diary-mode={diary.mode}
      data-testid="dungeon-diary"
    >
      <SummaryStrip diary={diary} />

      <div className={styles.body}>
        <div className={styles.manuscript}>
          {diary.floors.map((floor) => (
            <section className={styles.floor} key={floor.depth}>
              <h3>Floor {floor.depth}</h3>
              {floor.entries.length === 0 ? (
                <p className={styles.blank}>The page waits.</p>
              ) : (
                <ol>
                  {floor.entries.map((entry) => (
                    <li
                      className={[
                        styles.entry,
                        styles[kindClass(entry.kind)],
                      ]
                        .filter(Boolean)
                        .join(" ")}
                      data-entry-kind={entry.kind}
                      data-source-count={entry.sources.length}
                      key={entry.id}
                    >
                      <div>
                        <span>{entry.title}</span>
                        <time>t{entry.turn}</time>
                      </div>
                      <p>{entry.text}</p>
                    </li>
                  ))}
                </ol>
              )}
            </section>
          ))}
        </div>

        <aside className={styles.learnedNote} aria-label="What the dungeon learned">
          <h3>What the Deep keeps</h3>
          <p>{diary.learnedNote}</p>
        </aside>
      </div>
    </section>
  );
}

function SummaryStrip({ diary }: { readonly diary: DungeonDiary }) {
  return (
    <div className={styles.summaryStrip}>
      <Summary label="Outcome" value={diary.summary.outcome} />
      <Summary label="Depth" value={String(diary.summary.depth)} />
      <Summary label="Turns" value={String(diary.summary.turns)} />
      <Summary label="Kills" value={String(diary.summary.kills)} />
      <Summary label="Found" value={String(diary.summary.discoveries)} />
    </div>
  );
}

function Summary({
  label,
  value,
}: {
  readonly label: string;
  readonly value: string;
}) {
  return (
    <div>
      <span>{label}</span>
      <strong>{value}</strong>
    </div>
  );
}

const kindClass = (kind: DiaryEntryKind): keyof typeof styles => {
  switch (kind) {
    case "callback":
      return "callback";
    case "close_call":
      return "closeCall";
    case "discovery":
      return "discovery";
    case "floor":
      return "floorEntry";
    case "kill":
      return "kill";
    case "narration":
      return "narration";
    case "quest":
      return "quest";
  }
};
import { createElement } from "react";
import { renderToStaticMarkup } from "react-dom/server";
import { describe, expect, it } from "vitest";

import type { DungeonDiary } from "@harness/diary";

import { DiaryLayer } from "./DiaryLayer";
import { DiaryPanel } from "./DiaryPanel";

describe("DiaryPanel", () => {
  it("renders the summary strip, floor recap, source markers, and learned note", () => {
    const markup = renderToStaticMarkup(
      createElement(DiaryPanel, { diary: fixtureDiary, variant: "final" }),
    );

    expect(markup).toContain("Outcome");
    expect(markup).toContain("defeat");
    expect(markup).toContain("Floor 1");
    expect(markup).toContain("You keep one hand on the stair.");
    expect(markup).toContain('data-entry-kind="narration"');
    expect(markup).toContain('data-source-count="1"');
    expect(markup).toContain("What the Deep keeps");
    expect(markup).toContain("What the dungeon learned:");
  });

  it("renders the paused Tab layer with diary and artifact tabs", () => {
    const markup = renderToStaticMarkup(
      createElement(DiaryLayer, {
        diary: fixtureDiary,
        artifactModel: null,
        activeTab: "artifacts",
        onClose: () => undefined,
        onSelectTab: () => undefined,
      }),
    );

    expect(markup).toContain("The Deep&#x27;s manuscript");
    expect(markup).toContain('role="tab"');
